using System;

public class Calculator
{
    private int value;

    public Calculator Add(int value)
    {
        this.value += value;
        return this;
    }

    public Calculator Subtract(int value)
    {
        this.value -= value;
        return this;
    }

    public int Result() => this.value;
}

class Program
{
    static void Main()
    {
        int result = new Calculator()
            .Add(10)
            .Subtract(3)
            .Add(5)
            .Result();

        Console.WriteLine($"Result: {result}");  // 12
    }
}
